custom_defined_behaviors:
behaviors {
    behavior_layer_tap {
        flavor = "tap-preferred";
        tapping-term-ms = <200>;
        quick-tap-ms = <200>;
    };
};

behaviors {
    behavior_mod_tap {
        flavor = "tap-preferred";
        tapping-term-ms = <170>;
        quick-tap-ms = <170>;
    };
};

#define MY_KEYS_L 0 1 2 3 4  10 11 12 13 14 15    22 23 24 25 26 27    34 35 36 37 38 39    46 47 48 49 50 51   64 65 66 67 68 // left-hand keys
#define MY_KEYS_R 5 6 7 8 9    16 17 18 19 20 21    28 29 30 31 32 33    40 41 42 43 44 45    58 59 60 61 62 63    75 76 77 78 79  // right-hand keys
#define MY_THUMBS 52 53 54 55 56 57  69 70 71 72 73 74

behaviors {
        hml: left_positional_hold_tap {
            compatible = "zmk,behavior-hold-tap";
            #binding-cells = <2>;
            flavor = "balanced";
            tapping-term-ms = <190>;
            quick-tap-ms = <190>;                // repeat on tap-into-hold
            require-prior-idle-ms = <110>;
            bindings = <&kp>, <&kp>;
            hold-trigger-key-positions = <MY_KEYS_R MY_THUMBS>;
            hold-trigger-on-release;             // delay positional check until key-release
        };

        hmr: right_positional_hold_tap {
            compatible = "zmk,behavior-hold-tap";
            #binding-cells = <2>;
            flavor = "balanced";
            tapping-term-ms = <190>;
            quick-tap-ms = <190>;                // repeat on tap-into-hold
            require-prior-idle-ms = <110>;
            bindings = <&kp>, <&kp>;
            hold-trigger-key-positions = <MY_KEYS_L MY_THUMBS>;
            hold-trigger-on-release;             // delay positional check until key-release
        };
};
